sql.if:
AND (
    t.assignee_user_id = #{viewer_user_id}
    OR p.owner_user_id = #{viewer_user_id}
    OR EXISTS (
        SELECT 1
        FROM schedule_project_member pm
        WHERE pm.project_id = t.project_id
          AND pm.user_id = #{viewer_user_id}
    )
)

mapper.select:
SELECT n.node_id, n.task_id, n.parent_node_id, n.node_name, n.node_type, n.sort_order, n.depth, n.description, n.use_yn, COALESCE(child_counts.child_count, 0) AS child_count FROM task_node n INNER JOIN schedule_task t ON t.task_id = n.task_id INNER JOIN schedule_project p ON p.project_id = t.project_id LEFT JOIN ( SELECT parent_node_id, COUNT(*) AS child_count FROM task_node GROUP BY parent_node_id ) child_counts ON child_counts.parent_node_id = n.node_id
AND n.task_id = #{task_id}
ORDER BY n.depth ASC, n.parent_node_id NULLS FIRST, n.sort_order ASC, n.node_id ASC

SELECT nmv.node_id, nmv.node_metric_value_id, nmv.metric_def_id, d.metric_name, d.include_in_stats_yn, d.value_slot_count, d.display_order, nmv.value_1, nmv.value_2, nmv.value_3 FROM node_metric_value nmv INNER JOIN task_node n ON n.node_id = nmv.node_id INNER JOIN schedule_task t ON t.task_id = n.task_id INNER JOIN schedule_project p ON p.project_id = t.project_id INNER JOIN task_type_metric_def d ON d.metric_def_id = nmv.metric_def_id
AND n.task_id = #{task_id}
ORDER BY nmv.node_id ASC, d.display_order ASC, d.metric_def_id ASC

SELECT COALESCE(MAX(sort_order), 0) + 1
FROM task_node
WHERE task_id = #{task_id}


        AND parent_node_id IS NULL


        AND parent_node_id = #{parent_node_id}

SELECT COUNT(*)
FROM task_node
WHERE parent_node_id = #{_parameter}

